import{_ as o,o as r,c as t,a2 as a}from"./chunks/framework.D5wUhsuj.js";const v=JSON.parse('{"title":"Project Structure (Frontend)","description":"","frontmatter":{},"headers":[],"relativePath":"android/02-project-structure.md","filePath":"android/02-project-structure.md"}'),n={name:"android/02-project-structure.md"};function d(c,e,i,l,u,s){return r(),t("div",null,[...e[0]||(e[0]=[a('<h1 id="project-structure-frontend" tabindex="-1">Project Structure (Frontend) <a class="header-anchor" href="#project-structure-frontend" aria-label="Permalink to &quot;Project Structure (Frontend)&quot;">​</a></h1><p>Projekt využívá moderní adresářovou strukturu nástroje Vite. Nativní kód pro Android je generován a izolován, vývoj probíhá primárně ve složce <code>src/</code>.</p><h2 id="hlavni-adresare" tabindex="-1">Hlavní adresáře: <a class="header-anchor" href="#hlavni-adresare" aria-label="Permalink to &quot;Hlavní adresáře:&quot;">​</a></h2><ul><li><code>android/</code> - Nativní Android projekt (generováno Capacitorem, upravuje se jen minimálně)</li><li><code>public/</code> - Statické assety (např. logo.webp)</li><li><code>src/</code> - Zdrojové kódy React aplikace <ul><li><code>components/</code> - Znovupoužitelné UI prvky (např. BottomNav.js)</li><li><code>pages/</code> - Hlavní obrazovky (Dashboard, History, atd.)</li></ul></li><li><code>vite.config.js</code> - Konfigurace bundleru</li><li><code>tailwind.config.js</code> - Konfigurace vzhledu a barev</li></ul><p>Cílem je udržovat čisté oddělení komponent (znovupoužitelné UI) od stránek (logika obrazovky).</p>',5)])])}const _=o(n,[["render",d]]);export{v as __pageData,_ as default};
